const body = $json.body ?? $json;
const from = body.From ?? body.from ?? body.WaId ?? '';
const message = body.Body ?? body.body ?? body.ButtonText ?? body.ButtonPayload ?? '';
const messageSid = body.MessageSid ?? body.SmsMessageSid ?? '';
const messageType = (body.MessageType ?? '').toString().toLowerCase();
const mediaType = String(body.MediaContentType0 ?? '').toLowerCase();
const numMedia = parseInt(String(body.NumMedia ?? '0'), 10) || 0;
let tipo = 'text';
if (body.ButtonPayload || body.ButtonText) tipo = 'button_reply';
else if (messageType === 'audio' || (numMedia > 0 && mediaType.startsWith('audio'))) tipo = 'audio';
else if (messageType === 'image' || (numMedia > 0 && mediaType.startsWith('image'))) tipo = 'image';
const out = { telefono: from, mensaje: message, tipo, messageSid, twilioFrom: from };
if ((tipo === 'audio' || tipo === 'image') && body.MediaUrl0) {
  out.mediaUrl = body.MediaUrl0;
  out.mediaContentType = body.MediaContentType0 ?? (tipo === 'audio' ? 'audio/ogg' : 'image/jpeg');
}
return [{ json: out }];

function esc(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;');
}
const botones = Array.isArray($json.botones) ? $json.botones : [];
let texto = $json.respuesta || 'Tuve un problema. Intenta de nuevo en un momento.';
if (botones.length) {
  texto += '\n\nResponde: ' + botones.map((b) => b.titulo).join(' / ');
}
const twiml = `<?xml version="1.0" encoding="UTF-8"?><Response><Message>${esc(texto)}</Message></Response>`;
return [{ json: { twiml } }];
